import { execution } from '@dynatrace-sdk/automation-utils';
import { eventsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const timeFrameMs = parseInt(input.timeFrameMinutes || 1440) * 60 * 1000;
    const from = Date.now() - timeFrameMs;
    const to = Date.now();

    let eventSelector = undefined;
    let filters = [];

    if (input.eventType && input.eventType.trim() !== '') {
      filters.push(`type("${input.eventType}")`);  
    }
    if (input.entitySelector && input.entitySelector.trim() !== '') {
      filters.push(input.entitySelector);
    }

    if (filters.length > 0) {
      eventSelector = filters.join(' AND ');
    }

    const response = await eventsClient.getEvents({
      eventSelector: eventSelector,
      from: from,
      to: to,
      limit: parseInt(input.limit || 100)
    });

    const events = response.events || [];

    console.log(`Retrieved ${events.length} events`);

    return {
      totalEvents: events.length,
      events: events.map(e => ({
        eventId: e.eventId || 'N/A',
        eventType: e.eventType || 'UNKNOWN',
        title: e.title || 'N/A',
        timestamp: e.timestamp ? new Date(e.timestamp).toISOString() : 'N/A',
        entityId: e.entityId || 'N/A'
      }))
    };
  } catch (error) {
    console.error('Error querying events:', error);
    throw new Error(`Failed to query events: ${error}`);
  }
}
